添加Fragment绑定com/danale/edge/ui/common/dialog/AcceptConfirmLogoutFragment.kt
package com.danale.edge.ui.common.dialogimport android.app.Dialogimport android.content.Contextimport android.os.Bundleimport android.view.LayoutInflaterimport androidx.databinding.DataBindingUtilimport androidx.fragment.app.DialogFragmentimport com.danale.edge.R// Fragmentimport com.danale.edge.databinding.DialogConfirmLogoutBindingclass AcceptConfirmLogoutFragment (val callback: (Int) -&gt; Unit) : DialogFragment() {    companion object {      	// 定义两种操作         const val ACTION_CONFIRM_LOGOUT = 9001        const val ACTION_CANCEL_LOGOUT = 9002    }    override fun onCreateDialog(savedInstanceState: Bundle?): Dialog {        return AcceptConfirmLogout(            callback,            requireContext(),            R.style.Theme_ViewWorld_Dialog        ).apply {            window?.setBackgroundDrawableResource(R.drawable.bg_rounded_rect)        }    }    class AcceptConfirmLogout(        val callback: (Int) -&gt; Unit,        context: Context,        themeResId: Int    ) : Dialog(context, themeResId) {        val binding: DialogConfirmLogoutBinding  // binding        init {            binding = DataBindingUtil.inflate(                LayoutInflater.from(context),                R.layout.dialog_confirm_logout,                null,                false            )          	// 确认退出            binding.confirmAccept.setOnClickListener {                dismiss()                callback(ACTION_CONFIRM_LOGOUT)            }          	// 取消退出            binding.confirmCancel.setOnClickListener {                dismiss()                callback(ACTION_CANCEL_LOGOUT)            }            setContentView(binding.root)        }    }}



